#include <iostream>
using namespace std;
int n;
bool check(int num) {
    int old = num;
    int new_ = 0;
    while (num > 0) {
        new_ = new_ * 8 + (num % 8);
        num /= 8;
    }
    return old == new_;
}
int main() {;
    cin >> n;
    for (int i = 1; i * i <= n; ++i) {
        int square = i * i;
        if (check(square)) {
            cout << square << ' ';
        }
    }
    return 0;
}
